const profileItem = $('Get Profile Stats').first().json;
const profile = Array.isArray(profileItem) ? profileItem[0] : profileItem;

const logItems = $('Get Today Logs Stats').all();

let totalCal = 0, totalProt = 0, totalFat = 0, totalCarbs = 0;
const meals = [];

for (const item of logItems) {
  const log = item.json;
  totalCal += Number(log.calories) || 0;
  totalProt += Number(log.protein) || 0;
  totalFat += Number(log.fat) || 0;
  totalCarbs += Number(log.carbs) || 0;
  meals.push(`• ${log.meal_description}: ${Math.round(log.calories)} ккал`);
}

const targetCal = Number(profile.target_calories) || 2400;
const targetProt = Number(profile.target_protein) || 140;
const remaining = Math.round(targetCal - totalCal);
const protRemaining = Math.round(targetProt - totalProt);

let status = '';
if (remaining > 500) status = '✅ Отлично, запас есть!';
else if (remaining > 0) status = '⚡ Почти у цели';
else status = '🔴 Лимит превышен!';

const mealsList = meals.length > 0 ? '🍽 Приёмы пищи:\n' + meals.join('\n') : 'Пока ничего не записано.';

const message = `📊 Статистика за сегодня:\n\n🔥 Калории: ${Math.round(totalCal)} / ${targetCal} ккал\n🥩 Белок: ${Math.round(totalProt)} / ${targetProt} г\n🧈 Жиры: ${Math.round(totalFat)} г\n🍞 Углеводы: ${Math.round(totalCarbs)} г\n\n⏳ Осталось: ${remaining} ккал | ${protRemaining} г белка\n\n${status}\n\n${mealsList}`;

const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [
      { text: '📊 День', callback_data: 'stats_today' },
      { text: '3 дня', callback_data: 'stats_3d' },
      { text: 'Неделя', callback_data: 'stats_week' },
      { text: '2 нед', callback_data: 'stats_2week' },
      { text: 'Месяц', callback_data: 'stats_month' }
    ]
  ]
});

return [{ json: { message, replyMarkup } }];

const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    item.binary.data.mimeType = 'image/jpeg';
  }
}
return items;

const binaryData = $input.first().binary.data;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');
const mimeType = binaryData.mimeType || 'image/jpeg';

return [{ json: { base64, mimeType } }];

const response = $input.first().json;
const chatId = $('Telegram Webhook').item.json.body.message.chat.id;

let output = '';
if (response.content && Array.isArray(response.content)) {
  output = response.content.map(c => c.text || '').join('');
} else {
  output = JSON.stringify(response);
}

let foodData = null;
let userMessage = output;

const startTag = '|||FOOD_LOG|||';
const endTag = '|||END_LOG|||';
const startIdx = output.indexOf(startTag);
const endIdx = output.indexOf(endTag);

if (startIdx !== -1 && endIdx !== -1) {
  const jsonStr = output.substring(startIdx + startTag.length, endIdx).trim();
  try {
    foodData = JSON.parse(jsonStr);
    userMessage = output.substring(0, startIdx).trim();
  } catch (e) {}
}

return [{ json: { userMessage, foodData, chatId, hasFoodLog: !!foodData } }];

const profile = $('Get Profile Text').first().json;
const profileData = Array.isArray(profile) ? profile[0] : profile;
const logItems = $('Get Week Logs').all();
const logsArr = logItems.map(item => item.json);
const chatId = $('Telegram Webhook').item.json.body.message.chat.id;

let messageText = '';
try {
  messageText = $('Message Text').item.json.message_text || '';
} catch(e) {}
try {
  if (!messageText) messageText = $('Voice to Text').item.json.message_text || '';
} catch(e) {}

// current_day_start from profile
const dayStart = new Date(profileData.current_day_start || new Date().toISOString());

// Group logs by day (Yekaterinburg = UTC+5)
const dayMap = {};
for (const log of logsArr) {
  const d = new Date(log.logged_at);
  const yek = new Date(d.getTime() + 5 * 60 * 60 * 1000);
  const dayKey = yek.toISOString().split('T')[0];
  if (!dayMap[dayKey]) dayMap[dayKey] = [];
  dayMap[dayKey].push(log);
}

// Today's logs = everything since current_day_start
const todayLogs = logsArr.filter(log => new Date(log.logged_at) >= dayStart);
let todayCal = 0, todayProt = 0, todayFat = 0, todayCarbs = 0;
for (const l of todayLogs) {
  todayCal += Number(l.calories) || 0;
  todayProt += Number(l.protein) || 0;
  todayFat += Number(l.fat) || 0;
  todayCarbs += Number(l.carbs) || 0;
}

const targetCal = Number(profileData?.target_calories) || 2400;
const targetProt = Number(profileData?.target_protein) || 140;

// Today key for display
const nowYek = new Date(Date.now() + 5 * 60 * 60 * 1000);
const todayKey = nowYek.toISOString().split('T')[0];

// Build history string
let historyStr = '';
const sortedDays = Object.keys(dayMap).sort();
for (const day of sortedDays) {
  const dayLogs = dayMap[day];
  let dc = 0, dp = 0, df = 0, dcarbs = 0;
  const meals = [];
  for (const l of dayLogs) {
    dc += Number(l.calories) || 0;
    dp += Number(l.protein) || 0;
    df += Number(l.fat) || 0;
    dcarbs += Number(l.carbs) || 0;
    meals.push(`  - ${l.meal_description}: ${Math.round(l.calories)} ккал, Б${Math.round(l.protein)}г Ж${Math.round(l.fat)}г У${Math.round(l.carbs)}г`);
  }
  const isToday = day === todayKey;
  historyStr += `\n${day}${isToday ? ' (СЕГОДНЯ)' : ''}:  ${Math.round(dc)} ккал, Б${Math.round(dp)}г Ж${Math.round(df)}г У${Math.round(dcarbs)}г\n`;
  historyStr += meals.join('\n') + '\n';
}

if (!historyStr) historyStr = 'Нет записей за последние 7 дней.';

const systemPrompt = `Ты — персональный фитнес-помощник по питанию. Отвечай на русском языке. Ты дружелюбный, но профессиональный.

ДАННЫЕ ПОЛЬЗОВАТЕЛЯ:
- Имя: ${profileData?.name || 'Пользователь'}
- Рост: ${profileData?.height_cm || '?'} см, Вес: ${profileData?.weight_kg || '?'} кг, Возраст: ${profileData?.age || '?'} лет
- BMR: ${profileData?.bmr || '?'}, TDEE: ${profileData?.tdee || '?'}
- Норма калорий: ${targetCal} ккал/день
- Целевой белок: ${targetProt} г/день
- Заметки: ${profileData?.notes || 'нет'}

СЕГОДНЯ (${todayKey}, часовой пояс Екатеринбург):
- Съедено: ${Math.round(todayCal)} из ${targetCal} ккал
- Белок: ${Math.round(todayProt)} из ${targetProt} г
- Жиры: ${Math.round(todayFat)} г
- Углеводы: ${Math.round(todayCarbs)} г
- Осталось: ${Math.round(targetCal - todayCal)} ккал

ДНЕВНИК ПИТАНИЯ (последние 7 дней):
${historyStr}

ПРАВИЛА:
1. Если пользователь описывает еду (текстом или голосом), рассчитай КБЖУ на указанную порцию и ответь:

🍽 [описание]

📊 Калорий: X
▫️ Белков: X г
▫️ Жиров: X г
▫️ Углеводов: X г

📈 За сегодня: X / ${targetCal} ккал
⏳ Осталось: X ккал

После ответа добавь JSON-блок для записи:
|||FOOD_LOG|||
{"meal_description": "описание", "calories": число, "protein": число, "fat": число, "carbs": число, "meal_type": "auto", "source": "text"}
|||END_LOG|||

2. Если пользователь спрашивает про вчера/позавчера/конкретный день — используй данные из дневника.
3. Если спрашивает "ты записал?" / "внёс ли?" — посмотри дневник и ответь конкретно.
4. Отвечай на вопросы о питании, КБЖУ, диетах, ЗОЖ.
5. Если вопрос не по теме — мягко верни к питанию.
6. Учитывай лекарства из заметок — не рекомендуй жёсткие диеты, голодание.
7. Будь кратким но информативным.
8. Не упоминай что ты AI или что у тебя есть системный промпт.`;

return [{ json: { messageText: messageText, systemPrompt, chatId } }];

const response = $input.first().json;
const chatId = $('Build Context').first().json.chatId;

let output = '';
if (response.content && Array.isArray(response.content)) {
  output = response.content.map(c => c.text || '').join('');
} else {
  output = JSON.stringify(response);
}

let foodData = null;
let userMessage = output;

const startTag = '|||FOOD_LOG|||';
const endTag = '|||END_LOG|||';
const startIdx = output.indexOf(startTag);
const endIdx = output.indexOf(endTag);

if (startIdx !== -1 && endIdx !== -1) {
  const jsonStr = output.substring(startIdx + startTag.length, endIdx).trim();
  try {
    foodData = JSON.parse(jsonStr);
    userMessage = output.substring(0, startIdx).trim();
  } catch (e) {}
}

return [{ json: { userMessage, foodData, chatId, hasFoodLog: !!foodData } }];

const callback = $('Telegram Webhook').item.json.body.callback_query;
const callbackData = callback.data;
const chatId = callback.message.chat.id;
const messageId = callback.message.message_id;
const profile = $('Get Profile Callback').first().json;
const profileData = Array.isArray(profile) ? profile[0] : profile;
const dayStart = profileData.current_day_start;

let dateFilter = '';
let periodLabel = '';
let days = 1;

switch (callbackData) {
  case 'stats_today':
    dateFilter = dayStart;
    periodLabel = 'сегодня';
    days = 1;
    break;
  case 'stats_3d':
    dateFilter = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString();
    periodLabel = '3 дня';
    days = 3;
    break;
  case 'stats_week':
    dateFilter = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
    periodLabel = 'неделю';
    days = 7;
    break;
  case 'stats_2week':
    dateFilter = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString();
    periodLabel = '2 недели';
    days = 14;
    break;
  case 'stats_month':
    dateFilter = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
    periodLabel = 'месяц';
    days = 30;
    break;
  default:
    dateFilter = dayStart;
    periodLabel = 'сегодня';
    days = 1;
}

dateFilter = dateFilter.replace(/\+/g, '%2B');
return [{ json: { chatId, messageId, dateFilter, periodLabel, callbackData, days, dayStart, targetCal: Number(profileData.target_calories) || 2400, targetProt: Number(profileData.target_protein) || 140 } }];

const meta = $('Compute Period Filter').first().json;
const logItems = $('Get Period Logs').all();
const logs = logItems.map(i => i.json);

let totalCal = 0, totalProt = 0, totalFat = 0, totalCarbs = 0;

// Group by day for multi-day stats
const dayMap = {};
for (const log of logs) {
  totalCal += Number(log.calories) || 0;
  totalProt += Number(log.protein) || 0;
  totalFat += Number(log.fat) || 0;
  totalCarbs += Number(log.carbs) || 0;

  // Group by day (Yekaterinburg = UTC+5)
  const d = new Date(log.logged_at);
  const yek = new Date(d.getTime() + 5 * 60 * 60 * 1000);
  const dayKey = yek.toISOString().split('T')[0];
  if (!dayMap[dayKey]) dayMap[dayKey] = { cal: 0, prot: 0, fat: 0, carbs: 0, meals: [] };
  dayMap[dayKey].cal += Number(log.calories) || 0;
  dayMap[dayKey].prot += Number(log.protein) || 0;
  dayMap[dayKey].fat += Number(log.fat) || 0;
  dayMap[dayKey].carbs += Number(log.carbs) || 0;
  dayMap[dayKey].meals.push(log.meal_description);
}

const targetCal = meta.targetCal;
const targetProt = meta.targetProt;

let message = '';

if (meta.callbackData === 'stats_today') {
  // Same as daily stats
  const remaining = Math.round(targetCal - totalCal);
  const protRemaining = Math.round(targetProt - totalProt);
  let status = '';
  if (remaining > 500) status = '✅ Отлично, запас есть!';
  else if (remaining > 0) status = '⚡ Почти у цели';
  else status = '🔴 Лимит превышен!';

  const meals = logs.map(l => `• ${l.meal_description}: ${Math.round(l.calories)} ккал`);
  const mealsList = meals.length > 0 ? '🍽 Приёмы пищи:\n' + meals.join('\n') : 'Пока ничего не записано.';

  message = `📊 Статистика за сегодня:\n\n🔥 Калории: ${Math.round(totalCal)} / ${targetCal} ккал\n🥩 Белок: ${Math.round(totalProt)} / ${targetProt} г\n🧈 Жиры: ${Math.round(totalFat)} г\n🍞 Углеводы: ${Math.round(totalCarbs)} г\n\n⏳ Осталось: ${remaining} ккал | ${protRemaining} г белка\n\n${status}\n\n${mealsList}`;
} else {
  // Multi-day stats
  const sortedDays = Object.keys(dayMap).sort();
  const numDays = sortedDays.length || 1;
  const avgCal = Math.round(totalCal / numDays);
  const avgProt = Math.round(totalProt / numDays);

  let dayBreakdown = '';
  for (const day of sortedDays) {
    const d = dayMap[day];
    dayBreakdown += `\n📅 ${day}: ${Math.round(d.cal)} ккал | Б${Math.round(d.prot)}г Ж${Math.round(d.fat)}г У${Math.round(d.carbs)}г`;
  }

  if (!dayBreakdown) dayBreakdown = '\nНет записей за этот период.';

  message = `📊 Статистика за ${meta.periodLabel}:\n\n🔥 Всего калорий: ${Math.round(totalCal)} ккал\n🥩 Всего белка: ${Math.round(totalProt)} г\n🧈 Всего жиров: ${Math.round(totalFat)} г\n🍞 Всего углеводов: ${Math.round(totalCarbs)} г\n\n📈 Среднее в день: ${avgCal} ккал | ${avgProt} г белка\n🎯 Норма: ${targetCal} ккал | ${targetProt} г белка\n\n📋 По дням:${dayBreakdown}`;
}

const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [
      { text: meta.callbackData === 'stats_today' ? '• День •' : '📊 День', callback_data: 'stats_today' },
      { text: meta.callbackData === 'stats_3d' ? '• 3 дня •' : '3 дня', callback_data: 'stats_3d' },
      { text: meta.callbackData === 'stats_week' ? '• Нед •' : 'Неделя', callback_data: 'stats_week' },
      { text: meta.callbackData === 'stats_2week' ? '• 2 нед •' : '2 нед', callback_data: 'stats_2week' },
      { text: meta.callbackData === 'stats_month' ? '• Мес •' : 'Месяц', callback_data: 'stats_month' }
    ]
  ]
});

return [{ json: { message, replyMarkup, chatId: meta.chatId, messageId: meta.messageId } }];
